// URL pública do WhatsApp worker (Railway), SEM barra no final.
// Necessário porque n8n 2.x pode bloquear $env (N8N_BLOCK_ENV_ACCESS_IN_NODE).
const WORKER_BASE_URL = 'https://adv-zazu-whatsapp-worker-production.up.railway.app';
const d = new Date();
d.setUTCDate(d.getUTCDate() - 1);
const date = d.toISOString().slice(0, 10);
const workerBaseUrl = WORKER_BASE_URL.replace(/\/$/, '');
return [{ json: { date, workerBaseUrl } }];

const reportDate = $('Set Date + Worker URL').first().json.date || '';
const item = $input.first().json;
const date = item.date || reportDate;
const groups = item.groups || [];
const err = item.error;

if (err) {
  return [{ json: { title: 'WhatsApp Grupos — resumo ' + date, content: '[Erro ao buscar mensagens] ' + err, _skipPost: false } }];
}

function fmtBR(ymd) {
  if (!ymd || ymd.length < 10) return ymd;
  return ymd.slice(8, 10) + '/' + ymd.slice(5, 7) + '/' + ymd.slice(0, 4);
}

const parts = [];
parts.push('Resumo dos grupos de WhatsApp em ' + fmtBR(date) + '.');
parts.push('');

if (groups.length === 0) {
  parts.push('Nenhuma mensagem no período ou grupos não configurados.');
} else {
  for (const g of groups) {
    parts.push('--- ' + (g.name || g.id) + ' ---');
    const msgs = g.messages || [];
    if (msgs.length === 0) {
      parts.push('(nenhuma mensagem do dia)');
    } else {
      for (const m of msgs) {
        const from = (m.from || '').replace(/@.*/, '');
        parts.push('[' + from + '] ' + (m.body || '').replace(/\n/g, ' '));
      }
    }
    parts.push('');
  }
}

const title = 'WhatsApp Grupos — resumo ' + fmtBR(date);
const content = parts.join('\n').slice(0, 50000);

return [{ json: { title, content, reportDate } }];
